    }


    [Fact]
    public void Has_Batch_Interface()
    {
        using var world = new World();

        world.Spawn().Add(ValA.New(0)).Add(ValB.New(1)).Add(ValC.New(2)).Add(ValD.New(3));

        var stream = world.Query<ValA, ValB, ValC, ValD>().Not<string>().Stream();
        var batch = stream.Batch();
        batch.Add<string>("visited");
        batch.Submit();

        var check = world.Query<ValA, ValB, ValC, ValD>().Compile();
        var i = 0;
        foreach (var entity in check)
        {
            i++;
            Assert.True(entity.Has<string>());
        }
        Assert.Equal(1, i);
    }
}

