    [Fact]
    public void Cannot_Run_Job_on_Wildcard_Query()
    {
        using var world = new World();
        world.Spawn().Add(RefA.New(0)).Add(RefB.New(1));

        var stream = world.Query<RefA, RefB>(Match.Any).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<RefA, RefB>(Match.Entity).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<RefA, RefB>(Match.Target).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<RefA, RefB>(Match.Object).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<RefA, RefB>(Match.Plain).Stream();
        var ran = false;
        stream.Job((ref c0, ref _) =>
        {
            output.WriteLine(c0.Value.ToString());
            ran = true;
        });
        Assert.True(ran);
    }


