    [Fact]
    public void Has_Batch_Interface()
    {
        using var world = new World();

        world.Spawn().Add(RefA.New(0)).Add(RefB.New(1)).Add(RefC.New(2)).Add(RefD.New(3)).Add(RefE.New(4));

        var stream = world.Query<RefA, RefB, RefC, RefD, RefE>().Not<string>().Stream();
        var batch = stream.Batch();
        batch.Add<string>("visited");
        batch.Submit();

        var check = world.Query<RefA, RefB, RefC, RefD, RefE>().Compile();
        var i = 0;
        foreach (var entity in check)
        {
            i++;
            Assert.True(entity.Has<string>());
        }
        Assert.Equal(1, i);
    }
}

