    [Theory]
    [ClassData(typeof(StreamCountGenerator))]
    public void All_Runners_Applicable(int count, bool createEmptyTable)
    {
        using var world = new World();

        var stream = world.Query<ValA, RefB, ValC>().Stream();

        //Create an empty table by spawning and despawning a single entity
        //that matches our test Query (but is a larger Archetype)
        if (createEmptyTable)
        {
            var dead = world.Spawn().Add(ValA.New(0)).Add(RefB.New(0)).Add(ValC.New(0)).Add(0.25f);
            world.Despawn(dead);
        }

        for (var index = 0; index < count; index++)
        {
            Assert.Equal(index, stream.Count);
            world.Spawn().Add(ValA.New(index)).Add(RefB.New(index)).Add(ValC.New(1));
        }

        stream.For((ref _, ref _, ref c2) =>
        {
            Assert.Equal(1, c2.Value);
            c2 = ValC.New(2);
        });

        stream.Raw((mem0, _, mem2) =>
        {
            for (var i = 0; i < count; i++)
            {
                Assert.Equal(i, mem0.Span[i].Value);
                Assert.Equal(2, mem2.Span[i].Value);
                mem2.Span[i] = ValC.New(3);
            }
        });

        stream.Raw((mem0, _, mem2) =>
        {
            for (var i = 0; i < count; i++)
            {
                Assert.Equal(i, mem0.Span[i].Value);
                Assert.Equal(3, mem2.Span[i].Value);
                mem2.Span[i] = ValC.New(4);
            }
        });

        stream.Job((ref _, ref _, ref c2) =>
        {
            Assert.Equal(4, c2.Value);
            c2 = ValC.New(5);
        });

        stream.Job(6, (uniform, ref _, ref _, ref c2) =>
        {
            Assert.Equal(5, c2.Value);
            c2 = ValC.New(uniform);
        });

        stream.For(7, (uniform, ref _, ref _, ref c2) =>
        {
            Assert.Equal(6, c2.Value);
            c2 = ValC.New(uniform);
        });

        stream.Raw(8, (uniform, _, _, mem2) =>
        {
            for (var i = 0; i < count; i++)
            {
                Assert.Equal(7, mem2.Span[i].Value);
                mem2.Span[i] = ValC.New(uniform);
            }
        });

        stream.Raw(9, (uniform, _, _, mem2) =>
        {
            for (var i = 0; i < count; i++)
            {
                Assert.Equal(8, mem2.Span[i].Value);
                mem2.Span[i] = ValC.New(uniform);
            }
        });

        stream.For((in e, ref _, ref _, ref c2) =>
        {
            Assert.True(e.Alive);
            Assert.Equal(9, c2.Value);
            c2 = ValC.New(10);
        });

        stream.For(11, (uniform, in _, ref _, ref _, ref c2) =>
        {
            Assert.Equal(10, c2.Value);
            c2 = ValC.New(uniform);
        });

        stream.For((ref _, ref _, ref c2) => { Assert.Equal(11, c2.Value); });
    }


    [Theory]
    [ClassData(typeof(StreamCountGenerator))]
    public void Query_Count_Accurate(int count, bool createEmptyTable)
    {
        using var world = new World();

        if (createEmptyTable)
        {
            var dead = world.Spawn().Add(ValA.New(0)).Add(RefB.New(0)).Add(ValC.New(0)).Add(0.25f);
            world.Despawn(dead);
        }

        List<Entity> entities = new(count);

        var stream = world.Query<ValA, RefB, ValC>().Stream();
        Assert.Equal(0, stream.Count);

        for (var index = 0; index < count; index++)
        {
            Assert.Equal(index, stream.Count);
            entities.Add(world.Spawn().Add(ValA.New(index)).Add(RefB.New(index)).Add(ValC.New(index)));
        }

        Assert.Equal(count, stream.Count);

        var random = new Random(69 + count);

        for (var i = count; i > 0; i--)
        {
            Assert.Equal(i, stream.Count);
            var removalIndex = random.Next(entities.Count);
            var removalEntity = entities[removalIndex];
            entities.RemoveAt(removalIndex);
            world.Despawn(removalEntity);
        }

        Assert.Equal(0, stream.Count);
    }


