                Assert.Equal(i, mem0.Span[i].Value);
                mem4.Span[i] = ValE.New(i + count);
            }
        });

        stream.Raw((mem0, _, _, _, mem4) =>
        {
            for (var i = 0; i < count; i++)
            {
                Assert.Equal(i, mem0.Span[i].Value);
                Assert.Equal(i + count, mem4.Span[i].Value);
            }
        });
    }


    [Theory]
    [ClassData(typeof(StreamCountGenerator))]
    public void Run_Visits_All_Entities_in_Order(int count, bool createEmptyTable)
    {
        using var world = new World();

        if (createEmptyTable)
        {
            var dead = world.Spawn().Add(ValA.New(0)).Add(RefB.New(0)).Add(ValC.New(0)).Add(RefD.New(0)).Add(ValE.New(0)).Add(0.25f);
            world.Despawn(dead);
        }

        for (var c = 0; c < count; c++)
            world.Spawn().Add(ValA.New(0)).Add(RefB.New(0)).Add(ValC.New(0)).Add(RefD.New(0)).Add(ValE.New(0));

        var stream = world.Query<ValA, RefB, ValC, RefD, ValE>().Stream();

        var processed = 0;
        stream.Raw((_, _, _, _, mem4) =>
        {
            foreach (ref var value in mem4.Span) value = ValE.New(processed++);
        });

        Assert.Equal(count, processed);

        stream.Raw((_, _, _, _, mem4) =>
        {
            Assert.Equal(count, mem4.Length);
            for (var i = 0; i < count; i++) Assert.Equal(i, mem4.Span[i].Value);
        });

        var index = 0;
        stream.For((ref _, ref _, ref _, ref _, ref c4) => { Assert.Equal(index++, c4.Value); });

        var index2 = 0;
        stream.For(1337, (_, ref _, ref _, ref _, ref _, ref c4) => { Assert.Equal(index2++, c4.Value); });
    }


