    [Fact]
    public void Cannot_Run_Job_on_Wildcard_Query()
    {
        using var world = new World();
        world.Spawn().Add(ValA.New(0)).Add(RefB.New(1)).Add(ValC.New(2)).Add(RefD.New(3)).Add(ValE.New(4));

        var stream = world.Query<ValA, RefB, ValC, RefD, ValE>(Match.Any).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _, ref _, ref _, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<ValA, RefB, ValC, RefD, ValE>(Match.Entity).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _, ref _, ref _, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<ValA, RefB, ValC, RefD, ValE>(Match.Target).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _, ref _, ref _, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<ValA, RefB, ValC, RefD, ValE>(Match.Object).Stream();
        Assert.Throws<InvalidOperationException>(() => stream.Job((ref c0, ref _, ref _, ref _, ref _) => { output.WriteLine(c0.Value.ToString()); }));

        stream = world.Query<ValA, RefB, ValC, RefD, ValE>(Match.Plain).Stream();
        var ran = false;
        stream.Job((ref c0, ref _, ref _, ref _, ref _) =>
        {
            output.WriteLine(c0.Value.ToString());
            ran = true;
        });
        Assert.True(ran);
    }


