    [Fact]
    public void Has_Batch_Interface()
    {
        using var world = new World();

        world.Spawn().Add(ValA.New(0)).Add(RefB.New(1)).Add(ValC.New(2)).Add(RefD.New(3)).Add(ValE.New(4));

        var stream = world.Query<ValA, RefB, ValC, RefD, ValE>().Not<string>().Stream();
        var batch = stream.Batch();
        batch.Add<string>("visited");
        batch.Submit();

        var check = world.Query<ValA, RefB, ValC, RefD, ValE>().Compile();
        var i = 0;
        foreach (var entity in check)
        {
            i++;
            Assert.True(entity.Has<string>());
        }
        Assert.Equal(1, i);
    }
